465 /// Create a single-scalar clone of \p RepR for lane \p Lane.
466 static VPReplicateRecipe *cloneForLane(VPlan &Plan, VPBuilder &Builder,
467                                        Type *IdxTy, VPReplicateRecipe *RepR,
468                                        VPLane Lane) {
469   // Collect the operands at Lane, creating extracts as needed.
470   SmallVector<VPValue *> NewOps;
471   for (VPValue *Op : RepR->operands()) {
472     if (vputils::isSingleScalar(Op)) {
473       NewOps.push_back(Op);
474       continue;
475     }
476     if (Lane.getKind() == VPLane::Kind::ScalableLast) {
477       NewOps.push_back(
478           Builder.createNaryOp(VPInstruction::ExtractLastElement, {Op}));
479       continue;
480     }
481     // Look through buildvector to avoid unnecessary extracts.
482     if (match(Op, m_BuildVector())) {
483       NewOps.push_back(
484           cast<VPInstruction>(Op)->getOperand(Lane.getKnownLane()));
485       continue;
486     }
487     VPValue *Idx =
488         Plan.getOrAddLiveIn(ConstantInt::get(IdxTy, Lane.getKnownLane()));
489     VPValue *Ext = Builder.createNaryOp(Instruction::ExtractElement, {Op, Idx});
490     NewOps.push_back(Ext);
491   }
492 
493   auto *New =
494       new VPReplicateRecipe(RepR->getUnderlyingInstr(), NewOps,
495                             /*IsSingleScalar=*/true, /*Mask=*/nullptr, *RepR);
496   New->transferFlags(*RepR);
497   New->insertBefore(RepR);
498   return New;
499 }
