1256 void VPInstructionWithType::execute(VPTransformState &State) {
1257   State.setDebugLocFrom(getDebugLoc());
1258   if (isScalarCast()) {
1259     Value *Op = State.get(getOperand(0), VPLane(0));
1260     Value *Cast = State.Builder.CreateCast(Instruction::CastOps(getOpcode()),
1261                                            Op, ResultTy);
1262     State.set(this, Cast, VPLane(0));
1263     return;
1264   }
1265   switch (getOpcode()) {
1266   case VPInstruction::StepVector: {
1267     Value *StepVector =
1268         State.Builder.CreateStepVector(VectorType::get(ResultTy, State.VF));
1269     State.set(this, StepVector);
1270     break;
1271   }
1272   default:
1273     llvm_unreachable("opcode not implemented yet");
1274   }
