1055   /// \returns True if instruction \p I can be truncated to a smaller bitwidth
1056   /// for vectorization factor \p VF.
1057   bool canTruncateToMinimalBitwidth(Instruction *I, ElementCount VF) const {
1058     return VF.isVector() && MinBWs.contains(I) &&
